mapper.select:

 SELECT * FROM ( SELECT rownum rn, TB.* FROM (
	SELECT /*selectBeautyPaymanetList*/
		 A.SEQ
		,TO_CHAR(TO_DATE(A.PM_DATE,'yyyy-mm-dd'),'yyyy') AS PM_YEAR
		,TO_CHAR(TO_DATE(A.PM_DATE,'yyyy-mm-dd'),'mm') AS PM_MONTH
		,TO_CHAR(TO_DATE(A.PM_DATE,'yyyy-mm-dd'),'yyyy-mm-dd') AS PM_DATE
		,A.STYLE_TYPE
		,(SELECT CODE_NM FROM COMTCCMMNDETAILCODE WHERE CODE_ID='STYLE' AND CODE=A.STYLE_TYPE) AS STYLE_TYPE_NM
		,A.PM_TYPE
		,(SELECT CODE_NM FROM COMTCCMMNDETAILCODE WHERE CODE_ID='PMTYPE' AND CODE=A.PM_TYPE) AS PM_TYPE_NM
		,A.PM_PRICE
		,A.IDX
		,TO_CHAR(A.REG_DATE,'yyyy-mm-dd') AS REG_DATE
	FROM BEAUTY_SALON_PAYMANET_INFO A
	WHERE 1=1
	AND TO_CHAR(TO_DATE(A.PM_DATE,'yyyy-mm-dd'),'yyyy') = #{searchYear}


		AND TO_NUMBER(TO_CHAR(TO_DATE(A.PM_DATE,'YYYY-MM-DD'),'MM')) = #{searchMonth}


		AND A.PM_DATE = #{searchDate}


		AND A.STYLE_TYPE = #{searchStyle}


		AND A.PM_TYPE = #{searchPmType}


	ORDER BY A.PM_DATE , A.IDX
	 ) TB 
	 )  WHERE rn BETWEEN #{firstIndex} + 1 AND #{firstIndex} + #{recordCountPerPage}


SELECT /*selectBeautyPaymanetListTotCnt*/
		COUNT(A.SEQ) AS CNT
	FROM BEAUTY_SALON_PAYMANET_INFO A
	WHERE 1=1
	AND TO_CHAR(TO_DATE(A.PM_DATE,'yyyy-mm-dd'),'yyyy') = #{searchYear}


		AND TO_NUMBER(TO_CHAR(TO_DATE(A.PM_DATE,'YYYY-MM-DD'),'MM')) = #{searchMonth}


		AND A.PM_DATE = #{searchDate}


		AND A.STYLE_TYPE = #{searchStyle}


		AND A.PM_TYPE = #{searchPmType}

