/*updateBeautyPaymanet*/
	UPDATE BEAUTY_SALON_PAYMANET_INFO
	SET 	PM_DATE = #{pmDate},
			STYLE_TYPE = #{styleType},
			PM_TYPE = #{pmType},
			PM_PRICE = #{pmPrice},
			IDX = #{idx}
	WHERE SEQ = #{seq}

mapper.select:

    SELECT 
        TO_NUMBER(SUBSTR(T.MONTH, 6, 2)) AS "dateLabel",
        NVL(SUM(S.PM_PRICE), 0) AS "statValue"
    FROM (
        /* 01~12월까지 가상 테이블 생성 */
        SELECT #{year} || '-' || LPAD(LEVEL, 2, '0') AS MONTH 
        FROM DUAL CONNECT BY LEVEL <= 12
    ) T
    LEFT OUTER JOIN BEAUTY_SALON_PAYMANET_INFO S ON SUBSTR(S.PM_DATE, 1, 7) = T.MONTH
    WHERE TO_CHAR(TO_DATE(S.PM_DATE,'YYYY-MM-DD'),'YYYY') = #{year}


		AND TO_NUMBER(TO_CHAR(TO_DATE(S.PM_DATE,'YYYY-MM-DD'),'MM')) = #{month}


		AND S.STYLE_TYPE = #{style}


		AND S.PM_DATE = #{searchDate}


    GROUP BY T.MONTH
    ORDER BY T.MONTH ASC

SELECT STYLE_TYPE AS "styleType", (SELECT CODE_NM FROM COMTCCMMNDETAILCODE WHERE CODE_ID='STYLE' AND CODE=A.STYLE_TYPE) AS STYLE_TYPE_NM, COUNT(*) AS "count", SUM(PM_PRICE) AS "totalPrice" FROM BEAUTY_SALON_PAYMANET_INFO A WHERE PM_DATE LIKE #{year} || '%' -- 특정 년도 검색 시
AND TO_NUMBER(TO_CHAR(TO_DATE(A.PM_DATE,'YYYY-MM-DD'),'MM')) = #{month}
AND A.STYLE_TYPE = #{style}
AND A.PM_DATE = #{searchDate}
GROUP BY STYLE_TYPE ORDER BY STYLE_TYPE
